import { Button, message } from 'antd';
import { SelectOutlined } from '@ant-design/icons';
import React, { useState, useRef, useEffect } from 'react';
import { FooterToolbar } from '@ant-design/pro-layout';
import type { ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { userGroupAddUsers, users, groups } from '@/services/api';
import { API } from '@/services/typings';
import { useModel } from '@umijs/max';
import { t, getTablePaginationConfig, GroupTypeUser, renderDetails, NamesPurpose_ChangeUserGroup } from '../../../global';
import { NameEditor } from '@/pages/DeviceList/DevicesTable';
import UserSelect from './UserSelect';
import { getLocalSortState, handleSortStateChange } from '@/components/Others/table_sort';
import { USER_LIST_SORT_STATE_KEY, userColumns } from '@/pages/UserList';
import { ModalForm } from '@ant-design/pro-form';
import { canChangeGroupOfUser, hasAnyPermChangeGroupOfUser as hasGlobalPermChangeGroupOfUser } from '@/pages/RoleList/permissionUtils';

type DeviceGroupDeviceListProps = {
  group: API.GroupListItem;
}
const DevicesTable: React.FC<DeviceGroupDeviceListProps> = (props) => {
  const actionRef = useRef<ActionType>();
  const [selectedRowsState, setSelectedRows] = useState<API.UserListItem[]>([]);
  const [moveGuids, setMoveGuids] = useState<string[]>([]);
  const [userSelectVisible, setUserSelectVisible] = useState<boolean>(false);
  const [MoveModalVisible, setMoveModalVisible] = useState<boolean>(false);
  const { initialState } = useModel('@@initialState');
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(USER_LIST_SORT_STATE_KEY));
  const [showDetail, setShowDetail] = useState<boolean>(false);
  const [currentRow, setCurrentRow] = useState<API.UserListItem>();

  useEffect(() => {
    actionRef.current?.reload();
  }, []);

  const handleMove = async (values: Record<string, any>, guids: string[]) => {
    const groupName = values.name;
    if (!groupName) {
      message.error(t("Please select a group"));
      return;
    }
    if (groupName === props.group.name) {
      message.warning(t("Same group"));
      return;
    }
    const hide = message.loading(t('Updating'));
    try {
      const params = {
        current: 1,
        pageSize: 1,
        type: GroupTypeUser,
        name: groupName,
      };
      const grps = await groups(params, undefined, true);
      if (grps.data?.length != 1) {
        hide();
        message.error(t("Unknown group"));
        return;
      }
      const target_grp = grps.data?.[0];
      if (!target_grp) {
        hide();
        message.error(t("Unknown group"));
        return;
      }
      if (target_grp.name !== groupName) {
        hide();
        message.error(t("Unknown group"));
        return;
      }
      await userGroupAddUsers(target_grp.guid, { data: guids });
      hide();
      message.success(`${guids.length} record${guids.length === 1 ? " is" : "s are"} successfully changed`);
    } catch (e: any) {
      hide();
      message.error(e);
    }
    actionRef.current?.clearSelected?.();
    actionRef.current?.reload();
    setMoveModalVisible(false);
  }

  const columns = userColumns({
    actionRef,
    myname: initialState?.user?.name,
    is_select: false,
    sortState,
    setSortState,
    onIdClick: (entity: API.UserListItem) => {
      setCurrentRow(entity);
      setShowDetail(true);
    },
  });

  return (
    <div>
      <ProTable<API.UserListItem, API.PageParams & { user_group_guid: string }>
        headerTitle={t('User List')}
        actionRef={actionRef}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'group_userlist_columns_state' }}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        params={{
          user_group_guid: props.group.guid,
        }}
        request={users}
        columns={columns}
        toolBarRender={hasGlobalPermChangeGroupOfUser(initialState?.user) ? () => [
          <Button
            type="primary"
            key="primary"
            onClick={() => {
              setUserSelectVisible(true);
            }}
          >
            <SelectOutlined /> {t('add_users')}
          </Button>,

        ] : undefined}
        rowSelection={
          hasGlobalPermChangeGroupOfUser(initialState?.user)
            ? {
              onChange: (_, selectedRows) => {
                setSelectedRows(selectedRows);
              },
            }
            : undefined
        }
        onChange={(_, __, sorter) => {
          handleSortStateChange(sorter, actionRef, USER_LIST_SORT_STATE_KEY, setSortState);
        }}
        pagination={getTablePaginationConfig("group_user_list")}
      />
      {selectedRowsState?.length > 0 && selectedRowsState.every((x) => canChangeGroupOfUser(initialState?.user, x)) && (
        <FooterToolbar
          extra={
            <div>
              {t('Chosen')} <a style={{ fontWeight: 600 }}>{selectedRowsState.length}</a>{' '}
              {t('Items')}
            </div>
          }
        >
          <Button onClick={() => {
            setMoveGuids(selectedRowsState.map(row => row.guid));
            setMoveModalVisible(true);
          }}>{t('move_to')}</Button>
        </FooterToolbar>
      )}
      <UserSelect
        visible={userSelectVisible}
        setVisible={setUserSelectVisible}
        groupGuid={props.group.guid}
        groupName={props.group.name}
        closeChangedCallback={() => {
          actionRef.current?.reload();
        }}
      ></UserSelect>
      <ModalForm
        title={t('move_to')}
        width="400px"
        open={MoveModalVisible}
        onOpenChange={setMoveModalVisible}
        onFinish={async (values) => {
          await handleMove(values, moveGuids);
        }}
        modalProps={{
          maskClosable: false,
          destroyOnClose: true,
          onCancel: () => {
            setMoveModalVisible(false);
          },
        }}
      >
        <NameEditor table={"grp"} field={"name"} label={"Group"} required type={GroupTypeUser} purpose={NamesPurpose_ChangeUserGroup} />
      </ModalForm>
      {renderDetails(
        showDetail,
        currentRow?.guid,
        currentRow,
        columns.slice(0, columns.length - 1),
        setCurrentRow,
        setShowDetail,
      )}
    </div>
  );
};

export default DevicesTable;
